def gen(rng, size):
    n = max(2, size)
    edges = []
    for i in range(n):
        if rng.random() < 0.2:
            edges.append(-1)
        else:
            t = rng.randrange(0, n)
            while t == i:
                t = rng.randrange(0, n)
            edges.append(t)
    node1 = rng.randrange(0, n)
    node2 = rng.randrange(0, n)
    return [edges, node1, node2]

