class Solution:
    def closestMeetingNode(self, edges, node1, node2):
        n = len(edges)
        def dists(start):
            d = [-1] * n
            cur = start
            step = 0
            while cur != -1 and d[cur] == -1:
                d[cur] = step
                step += 1
                cur = edges[cur]
            return d
        d1 = dists(node1)
        d2 = dists(node2)
        best = -1
        best_val = None
        for i in range(n):
            if d1[i] != -1 and d2[i] != -1:
                m = max(d1[i], d2[i])
                if best_val is None or m < best_val:
                    best_val = m
                    best = i
        return best

