class Solution:
    def closestMeetingNode(self, edges, node1, node2):
        n = len(edges)
        def walk(s):
            d = [-1] * n
            cur, step = s, 0
            while cur != -1 and d[cur] == -1:
                d[cur] = step
                cur = edges[cur]
                step += 1
            return d
        a = walk(node1)
        b = walk(node2)
        ans = -1
        cur_best = float('inf')
        for i in range(n):
            if a[i] != -1 and b[i] != -1:
                m = a[i] if a[i] > b[i] else b[i]
                if m < cur_best:
                    cur_best = m
                    ans = i
        return ans

