var closestMeetingNode = function(edges, node1, node2) {
    const n = edges.length;
    const walk = (s) => {
        const d = new Array(n).fill(-1);
        let cur = s, step = 0;
        while (cur !== -1 && d[cur] === -1) {
            d[cur] = step;
            cur = edges[cur];
            step += 1;
        }
        return d;
    };
    const a = walk(node1);
    const b = walk(node2);
    let ans = -1, best = Infinity;
    for (let i = 0; i < n; i++) {
        if (a[i] !== -1 && b[i] !== -1) {
            const m = Math.max(a[i], b[i]);
            if (m < best) { best = m; ans = i; }
        }
    }
    return ans;
};
